existing = {}
for entry in existing_lscolors.split(":"):
    if "=" in entry:
        k, v = entry.split("=", 1)
        existing[k] = v


def stable_color(key: str) -> tuple[int, int, int]:
    h = hashlib.sha256(key.encode()).digest()
    return (
        h[0] % 196 + 60,
        h[1] % 196 + 60,
        h[2] % 196 + 60,
    )


added = []
for ext in extensions:
    k = f"*{ext}"
    if k not in existing:
        r, g, b = stable_color(ext)
        added.append(f"{k}=01;38;2;{r};{g};{b}")
merged = existing_lscolors.rstrip(":")
if added:
    merged += ":" + ":".join(added)
pathlib.Path("newlscolors").write_text(merged, encoding="utf-8")
print(merged)
